package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AbstractGewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BepaalAardCodeExtensieData;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CodeExtensie;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Rekenwijze;
import be.schaubroeck.lpb.tools.enumtypes.RszppoKategorie;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetal;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuut;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutFactory;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutOpProefBenoemd;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutOpProefBenoemdFactory;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelselFactory;
import be.schaubroeck.lpb.tools.rsz.Statuut;
import be.schaubroeck.lpb.tools.rsz.dmfappl.CategorieKengetalDmfappl;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;

public class GewoonLoonDmfappl extends AbstractGewoonLoon {
    public static final LocalDate NIEUWE_REGELING_501_502 = new LocalDate(2007, 1, 1);
    public static final LocalDate AFSCHAFFEN_LOONCODE_921 = new LocalDate(2011, 1, 1);
    public static final int AFWEZIGHEIDSCODE_180 = 180;
    public static final Integer MRA_503 = 503;

    private final LocalDateInterval rekenPeriode;

    public GewoonLoonDmfappl(LoonCodeManager loonCodeManager, LocalDateInterval rekenPeriode) {
        super(loonCodeManager, rekenPeriode);
        this.rekenPeriode = rekenPeriode;
    }

    public LocalDateInterval getRekenPeriode() {
        return rekenPeriode;
    }

    public AardKodeExtensie bepaalAardKodeExtensie(SleutelGegevens gegevens) {

        CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel = getCategorieKengetalStatuutPensioenstelsel(gegevens);

        BepaalAardCodeExtensieData bepaalAardCodeExtensieData = BepaalAardCodeExtensieData.builder()
                .afwezigheidsCode(gegevens.getAfwezigheidsCode())
                .categorieKengetalStatuutPensioenstelsel(categorieKengetalStatuutPensioenstelsel)
                .hoedanigheid(gegevens.getHoedanigheid())
                .mra1(gegevens.getMaatregelingReorganisatieArbeidsTijd())
                .mra2(gegevens.getMaatregelingReorganisatieArbeidsTijd2())
                .rekenwijze(gegevens.getRekenWijze())
                .build();
        return bepaalAardKodeExtensieGewoonLoonDmfappl(bepaalAardCodeExtensieData);
    }

    public CategorieKengetalStatuutPensioenstelsel getCategorieKengetalStatuutPensioenstelsel(SleutelGegevens gegevens) {
        CategorieKengetal categorieKengetal = new CategorieKengetalDmfappl(gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal());
        CategorieKengetalStatuut categorieKengetalStatuut = CategorieKengetalStatuutFactory.getCategorieKengetalStatuut(
                rekenPeriode.getStart(), categorieKengetal, gegevens.getStatuutDmfappl());
        return CategorieKengetalStatuutPensioenstelselFactory.create(rekenPeriode.getStart(), categorieKengetalStatuut, gegevens.getPensioenStelsel());
    }

    public AardKodeExtensie bepaalAardKodeExtensieGewoonLoonDmfappl(BepaalAardCodeExtensieData bepaalAardCodeExtensieData) {
        CodeExtensie looncode = CodeExtensie.GEWOON_LOON;

        CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel = bepaalAardCodeExtensieData.getCategorieKengetalStatuutPensioenstelsel();
        CategorieKengetalStatuut categorieKengetalStatuut = categorieKengetalStatuutPensioenstelsel.getCategorieKengetalStatuut();
        WerkgeversCategorie werkgeversCategorie = categorieKengetalStatuut.getWerkgeversCategorie();
        boolean vastbenoemd = categorieKengetalStatuutPensioenstelsel.isVastbenoemd();
        DmfapplStatuutDmfappl statuutDmfappl = categorieKengetalStatuut.getStatuutDmfappl();

        DmfapplWnkengetal dmfapplWnkengetal = categorieKengetalStatuut.getDmfapplWnkengetal();

        CategorieKengetalStatuutOpProefBenoemd categorieKengetalStatuutOpProefBenoemd =
                CategorieKengetalStatuutOpProefBenoemdFactory.create(rekenPeriode.getStart(), categorieKengetalStatuut, bepaalAardCodeExtensieData.getOpProefBenoemd());

        Hoedanigheid hoedanigheid = bepaalAardCodeExtensieData.getHoedanigheid();

        if (vastbenoemd && rekenPeriode.getStart().compareTo(START_NIEUWE_CODE_DISPO) < 0
                && bepaalAardCodeExtensieData.getAfwezigheidsCode() == AFWEZIGHEIDSCODE_180) {
            looncode = CodeExtensie.GEWOON_LOON_EXT_171;
        } else if (vastbenoemd && rekenPeriode.getStart().compareTo(START_NIEUWE_CODE_DISPO) >= 0
                && (MRA_503.equals(bepaalAardCodeExtensieData.getMra1()) || MRA_503.equals(bepaalAardCodeExtensieData.getMra2()))) {
            looncode = CodeExtensie.GEWOON_LOON_170;
        } else if (hoedanigheid == Hoedanigheid.WACHTWEDDEN) {
            looncode = CodeExtensie.WACHTWEDDE;
        } else if (hoedanigheid == Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES && bepaalAardCodeExtensieData.getRekenwijze() == Rekenwijze.MAAND
                && bepaalAardCodeExtensieData.getStatuut().isPersoneelOnderwijs()) {
            looncode = bepaalKodeExtensieGewoonLoonOnderwijzendPersoneel(categorieKengetalStatuutOpProefBenoemd);
        } else if (isGeneesheer(hoedanigheid, statuutDmfappl) && (categorieKengetalStatuut.isGeneesheerConditie1() || isGeneesheerConditie2(
                werkgeversCategorie, dmfapplWnkengetal))) {
            if (rekenPeriode.getEnd().isBefore(AFSCHAFFEN_LOONCODE_921)) {
                looncode = CodeExtensie.GENEESHEER_OUD;
            } else {
                looncode = CodeExtensie.GENEESHEER;
            }
        } else if (hoedanigheid == Hoedanigheid.MANDATARISSEN) {
            looncode = getCodeExtensieMandataris(dmfapplWnkengetal);
        } else {
            if (hoedanigheid == Hoedanigheid.MANDATARISSEN_GEPENSIOENEERD || hoedanigheid == Hoedanigheid.WERKNEMERS_GEPENSIOENEERD) {
                looncode = CodeExtensie.PENSIOEN;
            }
        }

        return getVergoedingAke(AkeTijdperk.DMFAPPL, looncode);
    }

    protected CodeExtensie getCodeExtensieMandataris(DmfapplWnkengetal dmfapplWnkengetal) {
        return CodeExtensie.MANDATARIS;
    }

    @Override
    public AardKodeExtensie bepaalAardKodeExtensieGewoonLoonRszppo(
            RszppoKategorie categorie, Hoedanigheid hoedanigheid, Rekenwijze rekenwijze) {
        throw new MessageException("Rszppo in Dmfappl tijdperk mag nooit voorkomen.");
    }

    public boolean isGeneesheer(Hoedanigheid hoedanigheid, DmfapplStatuutDmfappl statuutDmfappl) {
        return hoedanigheid == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN && statuutDmfappl == DmfapplStatuutDmfappl.GENEESHEREN;
    }

    public boolean isGeneesheerConditie2(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal) {
        return (werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_OPENBAAR
                || werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENBAAR_ARBREG_OPENBAAR)
                && werknemersKengetal == DmfapplWnkengetal.CONTRACTUEEL_GENEESHEER_VRIJGESTELD_BIJDRAGEN;
    }

    private CodeExtensie bepaalKodeExtensieGewoonLoonOnderwijzendPersoneel(CategorieKengetalStatuutOpProefBenoemd categorieKengetalStatuutOpProefBenoemd) {
        CodeExtensie gewoonLoon = CodeExtensie.GEWOON_LOON;

        CategorieKengetalStatuut categorieKengetalStatuut = categorieKengetalStatuutOpProefBenoemd.getCategorieKengetalStatuut();
        CategorieKengetal categorieKengetal = categorieKengetalStatuut.getCategorieKengetal();
        WerkgeversCategorie werkgeversCategorie = categorieKengetal.getWerkgeversCategorie();

        Statuut statuut = categorieKengetalStatuut.getStatuut();
        if (rekenPeriode.getEnd().isBefore(NIEUWE_REGELING_501_502)) {
            if (werkgeversCategorie == WerkgeversCategorie.VASTBENOEMDEN_GEMEENSCHAPPELIJK_PENSIOENSTELSEL
                    && categorieKengetalStatuutOpProefBenoemd.isVastbenoemdKinderbijslagRszppo()) {
                gewoonLoon = CodeExtensie.TOEZICHT_VASTBENOEMD;
            } else {
                if (werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENBAAR_ARBREG_OPENBAAR
                        && categorieKengetalStatuut.isContractueelHoofdarbeiders()) {
                    gewoonLoon = CodeExtensie.TOEZICHT_CONTRACTUEEL;
                }
            }
        } else {
            if (categorieKengetalStatuutOpProefBenoemd.isToezicht()) {
                if (statuut.isToezichtVastbenoemd()) {
                    gewoonLoon = CodeExtensie.TOEZICHT_VASTBENOEMD;
                } else {
                    if (statuut.isPersoneelOnderwijsGeenDimona()) {
                        gewoonLoon = CodeExtensie.TOEZICHT_CONTRACTUEEL;
                    }
                }
            } else {
                if (werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENBAAR_ARBREG_OPENBAAR
                        && categorieKengetalStatuut.isContractueelHoofdarbeiders()
                        && statuut.isToezichtContractueel()) {
                    gewoonLoon = CodeExtensie.TOEZICHT_CONTRACTUEEL;
                }
            }
        }

        return gewoonLoon;
    }
}
